import{_ as r,o as e,c as d,ak as a}from"./chunks/framework.oFDsBAuP.js";const o="/settings/task/task-records.png",_=JSON.parse('{"title":"任务日志","description":"","frontmatter":{"title":"任务日志"},"headers":[],"relativePath":"settings/user/task.md","filePath":"settings/user/task.md"}'),s={name:"settings/user/task.md"};function n(c,t,h,i,l,g){return e(),d("div",null,[...t[0]||(t[0]=[a('<h2 id="任务日志" tabindex="-1">任务日志 <a class="header-anchor" href="#任务日志" aria-label="Permalink to &quot;任务日志&quot;">​</a></h2><p><strong>任务日志</strong>用于查看异步类能力的执行记录，例如 Midjourney 绘图、Suno 音乐生成、视频生成等：每条记录对应一次提交，可跟踪排队、进行与结束状态，并在成功后查看产出或失败原因。</p><p>进入方式：侧栏 <strong>任务日志</strong>，或访问 <a href="https://console.atomflow.org/console/task" target="_blank" rel="noreferrer">控制台 · 任务日志</a>。</p><p><img src="'+o+'" alt="任务记录：筛选与列表"></p><h3 id="列表与筛选" tabindex="-1"><a href="#列表与筛选">列表与筛选</a> <a class="header-anchor" href="#列表与筛选" aria-label="Permalink to &quot;[列表与筛选](#列表与筛选)&quot;">​</a></h3><p>页面上方通常会展示与当前时间范围相关的 <strong>消耗额度、RPM、TPM</strong> 等摘要（以实际控制台为准）。下方为任务表格，常见列包括：</p><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td>提交时间 / 结束时间</td><td>任务入队与完成时刻。</td></tr><tr><td>花费时间</td><td>从提交到结束所耗时长。</td></tr><tr><td>平台 / 类型</td><td>任务所属服务与业务类型。</td></tr><tr><td>任务 ID</td><td>唯一标识，便于在支持渠道侧对账或排障。</td></tr><tr><td>任务状态 / 进度</td><td>当前生命周期阶段与百分比等。</td></tr><tr><td>详情</td><td>展开可查看更完整的请求与返回信息（若有）。</td></tr></tbody></table><p>在筛选区选择 <strong>时间范围</strong>、填写 <strong>任务 ID</strong> 后点击 <strong>「查询」</strong>；<strong>「重置」</strong> 可清空条件。<strong>「列设置」</strong> 可按个人习惯隐藏或固定部分列；<strong>「紧凑列表」</strong> 可切换更紧凑的行高以便一屏浏览更多行。</p><h3 id="任务状态说明" tabindex="-1"><a href="#任务状态说明">任务状态说明</a> <a class="header-anchor" href="#任务状态说明" aria-label="Permalink to &quot;[任务状态说明](#任务状态说明)&quot;">​</a></h3><p>不同产品线的状态文案可能略有差异，常见含义如下：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><code>PENDING</code></td><td>已提交，等待调度或排队中。</td></tr><tr><td><code>IN_PROGRESS</code></td><td>正在生成或处理中。</td></tr><tr><td><code>SUCCESS</code></td><td>已完成，可在详情或关联入口查看结果。</td></tr><tr><td><code>FAILURE</code></td><td>失败结束；若平台支持自动退费，配额会按规则退回（以实际提示为准）。</td></tr></tbody></table><p>若长时间停留在 <code>PENDING</code> 或 <code>IN_PROGRESS</code>，可先确认上游渠道与账户额度是否正常，再结合 <strong>任务 ID</strong> 联系支持或管理员排查。</p>',12)])])}const b=r(s,[["render",n]]);export{_ as __pageData,b as default};
